// Nó C02: Valida HMAC do Chatwoot e filtra apenas conversation_resolved
const crypto = require('crypto');

const body = $input.first().json;
const headers = body.headers || {};

// --- HMAC validation (Chatwoot assina com CHATWOOT_HMAC_SECRET) ---
const secret = $env.CHATWOOT_HMAC_SECRET;
const sig = headers['x-chatwoot-signature'] || headers['X-Chatwoot-Signature'] || '';
if (secret && sig) {
  const payload = JSON.stringify(body.body !== undefined ? body.body : body);
  const expected = crypto.createHmac('sha256', secret).update(payload).digest('hex');
  if (expected !== sig) {
    throw new Error('HMAC Chatwoot inválido — requisição rejeitada');
  }
}

// --- Filtrar apenas conversation_resolved ---
const event = body?.event;
if (event !== 'conversation_resolved') {
  return [{ json: { action: 'stop', event } }];
}

// --- Extrair remotejid do contato (Chatwoot identifier = remotejid) ---
// O identifier foi setado no handoff_humano como o remotejid do WhatsApp
const identifier =
  body?.conversation?.meta?.sender?.identifier ||
  body?.contact?.identifier ||
  body?.meta?.sender?.identifier ||
  '';

if (!identifier) {
  // Sem identifier, não conseguimos associar ao lead — para
  return [{ json: { action: 'stop', reason: 'semIdentifier', event } }];
}

const conversationId = body?.conversation?.id || body?.id || 0;

return [{
  json: {
    action: 'reativar',
    remotejid: identifier,
    conversa_chatwoot_id: conversationId,
  }
}];

// Nó C04: Seta ia_ativa=TRUE e insere msg system no histórico
// IARA não envia nada — só volta a ficar ativa para próximas mensagens do lead
const remotejid = $input.first().json.remotejid;
const conversaId = $input.first().json.conversa_chatwoot_id;

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const h = {
  apikey: supabaseKey,
  Authorization: `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
};

// UPDATE leads SET ia_ativa=TRUE
const updateRes = await fetch(
  `${supabaseUrl}/rest/v1/leads?remotejid=eq.${encodeURIComponent(remotejid)}`,
  {
    method: 'PATCH',
    headers: { ...h, Prefer: 'return=minimal' },
    body: JSON.stringify({ ia_ativa: true }),
  }
);
if (!updateRes.ok) {
  const err = await updateRes.text();
  throw new Error(`Falha ao reativar ia_ativa (${updateRes.status}): ${err}`);
}

// INSERT chat_messages role=system para marcar fim do handoff no histórico
const msgRes = await fetch(`${supabaseUrl}/rest/v1/chat_messages`, {
  method: 'POST',
  headers: h,
  body: JSON.stringify({
    remotejid,
    role: 'system',
    content: '[handoff encerrado pela equipe — IARA reativada]',
  }),
});
if (!msgRes.ok) {
  const err = await msgRes.text();
  throw new Error(`Falha ao inserir msg system (${msgRes.status}): ${err}`);
}

return [{
  json: {
    status: 'ok',
    remotejid,
    conversa_chatwoot_id: conversaId,
    mensagem: 'IARA reativada para próximas mensagens do lead',
  }
}];
